 27→@Injectable()
 28→export class CacheService {
 29→	private readonly logger = new Logger(CacheService.name);
 30→	private readonly redlock: Redlock;
 31→	private readonly redisWriteClient: Redis;
 32→	private readonly redisReadClient: Redis;
 33→	private readonly cacheWriteManager: Keyv;
 34→	private readonly cacheReadManager: Keyv;
 35→	private readonly recentWrites = new Map<string, number>();
 36→	private readonly CONSISTENCY_WINDOW_MS = 1000;
 37→	private isReadReplicaHealthy = true;
 38→
 39→	constructor(
 40→		@Inject(CACHE_WRITE_MANAGER) cacheWriteManager: Keyv,
 41→		@Inject(CACHE_READ_MANAGER) cacheReadManager: Keyv,
 42→		@Inject(REDIS_WRITE_CLIENT) redisWriteClient: Redis,
 43→		@Inject(REDIS_READ_CLIENT) redisReadClient: Redis,
 44→	) {
 45→		this.cacheWriteManager = cacheWriteManager;
 46→		this.cacheReadManager = cacheReadManager;
 47→		this.redisWriteClient = redisWriteClient;
 48→		this.redisReadClient = redisReadClient;
 49→		this.redlock = new Redlock([redisWriteClient], {
 50→			driftFactor: 0.01,
 51→			retryCount: 10,
 52→			retryDelay: 200,
 53→			retryJitter: 200,
 54→		});
 55→
 56→		this.setupHealthChecks();
 57→		this.startRecentWritesCleanup();
 58→	}
 59→
 60→	@LogExecution({
 61→		paramFormatter: (params) => params,
 62→		responseFormatter: () => '',
 63→	})
 64→	async get<T>({
 65→		namespace,
 66→		key,
 67→		consistency = ConsistencyLevel.EVENTUAL,
 68→	}: {
 69→		namespace: Namespaces;
 70→		key: string;
 71→		consistency?: ConsistencyLevel;
 72→	}): Promise<T | null> {
 73→		const namespacedKey = this.getNamespacedKey({ namespace, key });
 74→
 75→		const shouldReadFromMaster = this.shouldReadFromMaster({
 76→			key: namespacedKey,
 77→			consistency,
 78→		});
 79→		const cacheManager = shouldReadFromMaster
 80→			? this.cacheWriteManager
 81→			: this.cacheReadManager;
 82→		const source = shouldReadFromMaster ? 'master' : 'replica';
 83→
 84→		try {
 85→			const result = (await cacheManager.get(namespacedKey)) as T;
 86→
 87→			if (!result) {
 88→				this.logger.log('Cache miss', { namespace, key, consistency, source });
 89→				return null;
 90→			}
 91→
 92→			this.logger.log('Cache hit', { namespace, key });
 93→
 94→			return result;
 95→		} catch (error) {
 96→			const e = error as Error;
 97→			this.logger.error(`Error retrieving from cache: ${e.message}`, e.stack, { source });
 98→
 99→			if (!shouldReadFromMaster && this.isReadReplicaHealthy) {
100→				this.logger.warn('Read replica failed, falling back to master', {
101→					namespace,
102→					key,
103→				});
104→				this.isReadReplicaHealthy = false;
105→				return this.get({ namespace, key, consistency: ConsistencyLevel.STRONG });
106→			}
107→
108→			throw this.createCacheError({ code: 'CONNECTION_FAILED', originalError: e });
109→		}
110→	}
111→
112→	@LogExecution({
113→		paramFormatter: (params: {
114→			namespace: Namespaces;
115→			key: string;
116→			value: unknown;
117→			ttl?: number;
118→		}) => ({
119→			namespace: params.namespace,
120→			key: params.key,
121→			value: '***',
122→			ttl: params.ttl,
123→		}),
124→		responseFormatter: () => '',
125→	})
126→	async set({
127→		namespace,
128→		key,
129→		value,
130→		ttl,
131→	}: {
132→		namespace: Namespaces;
133→		key: string;
134→		value: unknown;
135→		ttl?: number;
136→	}): Promise<void> {
137→		const namespacedKey = this.getNamespacedKey({ namespace, key });
138→
139→		try {
140→			await this.cacheWriteManager.set(namespacedKey, value, ttl);
141→			this.trackRecentWrite({ key: namespacedKey });
142→			this.logger.log('Cached value', { namespace, key, ttl });
143→		} catch (error) {
144→			const e = error as Error;
145→			this.logger.error(`Error setting cache: ${e.message}`, e.stack);
146→			throw this.createCacheError({ code: 'OPERATION_FAILED', originalError: e });
147→		}
148→	}
149→
150→	@LogExecution({
151→		paramFormatter: (params) => params,
152→		responseFormatter: (res) => (res ? 'true' : 'false'),
153→	})
154→	async has({
155→		namespace,
156→		key,
157→	}: {
158→		namespace: Namespaces;
159→		key: string;
160→	}): Promise<boolean> {
161→		this.logger.log('Checking cache key existence', { namespace, key });
162→		const value = await this.get<unknown>({ namespace, key });
163→		return value !== null;
164→	}
165→
166→	@LogExecution({
167→		paramFormatter: (params) => params,
168→		responseFormatter: (res) => (res ? 'true' : 'false'),
169→	})
170→	async deleteOne({
171→		namespace,
172→		key,
173→	}: {
174→		namespace: Namespaces;
175→		key: string;
176→	}): Promise<boolean> {
177→		try {
178→			const namespacedKey = this.getNamespacedKey({ namespace, key });
179→			await this.cacheWriteManager.delete(namespacedKey);
180→			this.logger.log('Deleted cache key', { namespace, key });
181→			return true;
182→		} catch (error) {
183→			const e = error as Error;
184→			this.logger.error(`Error deleting from cache: ${e.message}`, e.stack);
185→			return false;
186→		}
187→	}
188→
189→	async incrementByOne({
190→		namespace,
191→		key,
192→	}: {
193→		namespace: Namespaces;
194→		key: string;
195→	}): Promise<void> {
196→		try {
197→			const namespacedKey = this.getNamespacedKey({ namespace, key });
198→			await this.redisWriteClient.incr(namespacedKey);
199→		} catch (error) {
200→			const e = error as Error;
201→			this.logger.error(`Error incrementing cache key: ${e.message}`, e.stack, {
202→				namespace,
203→				key,
204→			});
205→			throw error;
206→		}
207→	}
208→
209→	async deleteAll(): Promise<boolean> {
210→		try {
211→			await this.cacheWriteManager.clear();
212→
213→			await new Promise((resolve) => setTimeout(resolve, 100));
214→
215→			await this.cacheReadManager.clear();
216→			this.recentWrites.clear();
217→			this.logger.log('Cleared all cache');
218→			return true;
219→		} catch (error) {
220→			const e = error as Error;
221→			this.logger.error(`Error clearing cache: ${e.message}`, e.stack);
222→			return false;
223→		}
224→	}
225→
226→	async withLock<T>({
227→		lockKey,
228→		operation,
229→		ttl = 5000,
230→	}: {
231→		lockKey: string;
232→		operation: () => Promise<T>;
233→		ttl?: number;
234→	}): Promise<T> {
235→		this.logger.log('Acquiring lock', { lockKey, ttlMs: ttl });
236→		const lock = await this.redlock.acquire([lockKey], ttl);
237→
238→		try {
239→			return await operation();
240→		} finally {
241→			this.logger.log('Releasing lock', { lockKey });
242→			await lock.release();
243→		}
244→	}
245→
246→	async acquireLock({ lockKey, ttl }: { lockKey: string; ttl: number }): Promise<Lock> {
247→		try {
248→			this.logger.log('Acquiring lock', { lockKey, ttlMs: ttl });
249→			return await this.redlock.acquire([lockKey], ttl);
250→		} catch (error) {
251→			this.logger.error(`Failed to acquire lock: ${error}`);
252→			throw error;
253→		}
254→	}
255→
256→	async releaseLock({ lock }: { lock: Lock }): Promise<void> {
257→		try {
258→			this.logger.log('Releasing lock', { lockKey: lock.resources.join(',') });
259→			await lock.release();
260→		} catch (error) {
261→			this.logger.error(`Failed to release lock: ${error}`);
262→			throw error;
263→		}
264→	}
265→
266→	private getNamespacedKey({
267→		namespace,
268→		key,
269→	}: {
270→		namespace: Namespaces;
271→		key: string;
272→	}): string {
273→		return `${namespace}:${key}`;
274→	}
275→
276→	private shouldReadFromMaster({
277→		key,
278→		consistency,
279→	}: {
280→		key: string;
281→		consistency: ConsistencyLevel;
282→	}): boolean {
283→		if (consistency === ConsistencyLevel.STRONG) {
284→			return true;
285→		}
286→
287→		if (!this.isReadReplicaHealthy) {
288→			return true;
289→		}
290→
291→		const lastWriteTime = this.recentWrites.get(key);
292→		if (lastWriteTime) {
293→			const timeSinceWrite = Date.now() - lastWriteTime;
294→			return timeSinceWrite < this.CONSISTENCY_WINDOW_MS;
295→		}
296→
297→		return false;
298→	}
299→
300→	private trackRecentWrite({ key }: { key: string }): void {
301→		this.recentWrites.set(key, Date.now());
302→	}
303→
304→	private startRecentWritesCleanup(): void {
305→		setInterval(() => {
306→			const now = Date.now();
307→			for (const [key, timestamp] of this.recentWrites.entries()) {
308→				if (now - timestamp > this.CONSISTENCY_WINDOW_MS * 2) {
309→					this.recentWrites.delete(key);
310→				}
311→			}
312→		}, this.CONSISTENCY_WINDOW_MS).unref();
313→	}
314→
315→	private setupHealthChecks(): void {
316→		this.redisReadClient.on('error', (error) => {
317→			this.logger.error('Read replica connection error:', error);
318→			this.isReadReplicaHealthy = false;
319→		});
320→
321→		this.redisReadClient.on('ready', () => {
322→			this.logger.log('Read replica connection restored');
323→			this.isReadReplicaHealthy = true;
324→		});
325→
326→		this.redisWriteClient.on('error', (error) => {
327→			this.logger.error('Write client connection error:', error);
328→		});
329→	}
330→
331→	private createCacheError({
332→		code,
333→		originalError,
334→	}: {
335→		code: CacheError['code'];
336→		originalError?: Error;
337→	}): CacheError {
338→		const error = new Error(`Cache operation failed: ${code}`) as CacheError;
339→		error.code = code;
340→		if (originalError) {
341→			error.originalError = originalError;
342→		}
343→		return error;
344→	}
345→}
