export const REDIS_READ_CLIENT = 'REDIS_READ_CLIENT';
export const REDIS_WRITE_CLIENT = 'REDIS_WRITE_CLIENT';
export const CACHE_WRITE_MANAGER = 'CACHE_WRITE_MANAGER';
export const CACHE_READ_MANAGER = 'CACHE_READ_MANAGER';

export enum ConsistencyLevel {
	EVENTUAL = 'eventual',
	STRONG = 'strong',
}

export interface CacheError extends Error {
	code: 'CONNECTION_FAILED' | 'KEY_NOT_FOUND' | 'OPERATION_FAILED';
	originalError?: Error;
}

export enum Namespaces {
	SESSION = 'session',
	AUTH_CODE = 'auth-code',
	LINKING_TOKEN = 'linking-token',
	OAUTH_STATE = 'oauth-state',
}

import { createKeyv } from '@keyv/redis';
import { Global, Module } from '@nestjs/common';
import { Redis } from 'ioredis';

import {
	CACHE_READ_MANAGER,
	CACHE_WRITE_MANAGER,
	REDIS_READ_CLIENT,
	REDIS_WRITE_CLIENT,
} from '@modules/cache/cache.constant';
import { CacheService } from '@modules/cache/cache.service';

import {
	NODE_ENV,
	REDIS_READ_URL,
	REDIS_URL,
	SERVER_NAME,
} from '@constants/env-variables.constant';

import { getEnv } from '@utils/get-env-variable.util';

@Global()
@Module({
	providers: [
		CacheService,
		{
			provide: CACHE_WRITE_MANAGER,
			// eslint-disable-next-line custom-rules/require-object-params
			useFactory: () => {
				const namespace = `${getEnv<string>({ key: SERVER_NAME })}:${getEnv<string>({ key: NODE_ENV })}`;
				const cacheWriteUrl = getEnv<string>({ key: REDIS_URL });
				return createKeyv(cacheWriteUrl, {
					namespace,
					useUnlink: true,
					keyPrefixSeparator: ':',
				});
			},
		},
		{
			provide: CACHE_READ_MANAGER,
			// eslint-disable-next-line custom-rules/require-object-params
			useFactory: () => {
				const namespace = `${getEnv<string>({ key: SERVER_NAME })}:${getEnv<string>({ key: NODE_ENV })}`;
				const cacheReadUrl = getEnv<string>({ key: REDIS_READ_URL });
				return createKeyv(cacheReadUrl, {
					namespace,
					useUnlink: true,
					keyPrefixSeparator: ':',
				});
			},
		},
		{
			provide: REDIS_WRITE_CLIENT,
			// eslint-disable-next-line custom-rules/require-object-params
			useFactory: () => {
				const cacheUrl = getEnv<string>({ key: REDIS_URL });
				return new Redis(cacheUrl, {
					// eslint-disable-next-line custom-rules/require-object-params
					retryStrategy: (times) => {
						return Math.min(times * 50, 2000);
					},
					maxRetriesPerRequest: 3,
					enableReadyCheck: true,
					connectTimeout: 10000,
					lazyConnect: false,
					// eslint-disable-next-line custom-rules/require-object-params
					reconnectOnError: (err) => {
						const targetError = 'READONLY';
						return err.message.includes(targetError);
					},
				});
			},
		},
		{
			provide: REDIS_READ_CLIENT,
			// eslint-disable-next-line custom-rules/require-object-params
			useFactory: () => {
				const cacheReadUrl = getEnv<string>({ key: REDIS_READ_URL });
				return new Redis(cacheReadUrl, {
					// eslint-disable-next-line custom-rules/require-object-params
					retryStrategy: (times) => {
						return Math.min(times * 50, 2000);
					},
					maxRetriesPerRequest: 3,
					enableReadyCheck: true,
					connectTimeout: 10000,
					lazyConnect: false,
					readOnly: true,
				});
			},
		},
	],
	exports: [
		CacheService,
		REDIS_WRITE_CLIENT,
		REDIS_READ_CLIENT,
		CACHE_WRITE_MANAGER,
		CACHE_READ_MANAGER,
