})
export class CacheModule {}

import { Inject, Injectable, Logger } from '@nestjs/common';
import { Redis } from 'ioredis';
import Keyv from 'keyv';
import Redlock, { Lock } from 'redlock';

import {
	CACHE_READ_MANAGER,
	CACHE_WRITE_MANAGER,
	REDIS_READ_CLIENT,
	REDIS_WRITE_CLIENT,
} from '@modules/cache/cache.constant';
import {
	CacheError,
	ConsistencyLevel,
	Namespaces,
} from '@modules/cache/types/cache.interface';

export { ConsistencyLevel, CacheError } from '@modules/cache/types/cache.interface';

@Injectable()
export class CacheService {
	private readonly logger = new Logger(CacheService.name);
	private readonly redlock: Redlock;
	private readonly redisWriteClient: Redis;
	private readonly redisReadClient: Redis;
	private readonly cacheWriteManager: Keyv;
	private readonly cacheReadManager: Keyv;
	private readonly recentWrites = new Map<string, number>();
	private readonly CONSISTENCY_WINDOW_MS = 1000;
	private isReadReplicaHealthy = true;

	constructor(
		@Inject(CACHE_WRITE_MANAGER) cacheWriteManager: Keyv,
		@Inject(CACHE_READ_MANAGER) cacheReadManager: Keyv,
		@Inject(REDIS_WRITE_CLIENT) redisWriteClient: Redis,
		@Inject(REDIS_READ_CLIENT) redisReadClient: Redis,
	) {
		this.cacheWriteManager = cacheWriteManager;
		this.cacheReadManager = cacheReadManager;
		this.redisWriteClient = redisWriteClient;
		this.redisReadClient = redisReadClient;
		this.redlock = new Redlock([redisWriteClient], {
			driftFactor: 0.01,
			retryCount: 10,
			retryDelay: 200,
			retryJitter: 200,
		});

		this.setupHealthChecks();
		this.startRecentWritesCleanup();
	}

	async get<T>({
		namespace,
		key,
		consistencyLevel = ConsistencyLevel.EVENTUAL,
	}: {
		namespace: Namespaces;
		key: string;
		consistencyLevel?: ConsistencyLevel;
	}): Promise<T | null> {
		const namespacedKey = this.getNamespacedKey({ namespace, key });

		const readFromMaster = this.shouldReadFromMaster({
			namespace,
			key: namespacedKey,
			consistencyLevel,
		});
		const cacheManager = readFromMaster ? this.cacheWriteManager : this.cacheReadManager;
		const source = readFromMaster ? 'master' : 'replica';

		try {
			const result = (await cacheManager.get(namespacedKey)) as T;

			if (!result) {
				this.logger.log('Cache miss', { namespace, key, consistencyLevel, source });
				return null;
			}

			this.logger.log('Cache hit', { namespace, key });

			return result;
		} catch (error) {
			const e = error as Error;
			this.logger.error(`Error retrieving from cache: ${e.message}`, e.stack, { source });

			if (!readFromMaster && this.isReadReplicaHealthy) {
				this.logger.warn('Read replica failed, falling back to master', {
					namespace,
					key,
				});
				this.isReadReplicaHealthy = false;
				return this.get({ namespace, key, consistencyLevel: ConsistencyLevel.STRONG });
			}

			throw this.createCacheError({ code: 'CONNECTION_FAILED', originalError: e });
		}
	}

	async set({
		namespace,
		key,
		value,
		ttl,
	}: {
		namespace: Namespaces;
		key: string;
		value: unknown;
		ttl?: number;
	}): Promise<void> {
		const namespacedKey = this.getNamespacedKey({ namespace, key });

		try {
			await this.cacheWriteManager.set(namespacedKey, value, ttl);
			this.trackRecentWrite({ key: namespacedKey });
			this.logger.log('Cached value', { namespace, key, ttl });
		} catch (error) {
			const e = error as Error;
			this.logger.error(`Error setting cache: ${e.message}`, e.stack);
			throw this.createCacheError({ code: 'OPERATION_FAILED', originalError: e });
		}
	}

	async has({
		namespace,
		key,
	}: {
		namespace: Namespaces;
		key: string;
	}): Promise<boolean> {
		this.logger.log('Checking cache key existence', { namespace, key });
		const value = await this.get<unknown>({ namespace, key });
		return value !== null;
	}

	async deleteOne({
		namespace,
		key,
	}: {
		namespace: Namespaces;
		key: string;
	}): Promise<boolean> {
		try {
			const namespacedKey = this.getNamespacedKey({ namespace, key });
			await this.cacheWriteManager.delete(namespacedKey);
			this.logger.log('Deleted cache key', { namespace, key });
			return true;
		} catch (error) {
			const e = error as Error;
			this.logger.error(`Error deleting from cache: ${e.message}`, e.stack);
			return false;
		}
	}

	async deleteAll({ namespace }: { namespace: Namespaces }): Promise<boolean> {
		try {
			await this.cacheWriteManager.clear();

			await new Promise((resolve) => setTimeout(resolve, 100));

			await this.cacheReadManager.clear();
			this.recentWrites.clear();
			this.logger.log('Cleared all cache', { namespace });
			return true;
		} catch (error) {
			const e = error as Error;
			this.logger.error(`Error clearing cache: ${e.message}`, e.stack);
			return false;
		}
	}

	async incrementByOne({
		namespace,
		key,
	}: {
		namespace: Namespaces;
		key: string;
	}): Promise<void> {
		try {
			const namespacedKey = this.getNamespacedKey({ namespace, key });
			await this.redisWriteClient.incr(namespacedKey);
		} catch (error) {
			const e = error as Error;
			this.logger.error(`Error incrementing cache key: ${e.message}`, e.stack, {
				namespace,
				key,
			});
			throw error;
		}
	}

	async withLock<T>({
		lockKey,
		operation,
		ttl = 5000,
	}: {
		lockKey: string;
		operation: () => Promise<T>;
		ttl?: number;
	}): Promise<T> {
		this.logger.log('Acquiring lock', { lockKey, ttlMs: ttl });
		const lock = await this.redlock.acquire([lockKey], ttl);

		try {
			return await operation();
		} finally {
			this.logger.log('Releasing lock', { lockKey });
			await lock.release();
		}
	}

	async acquireLock({ lockKey, ttl }: { lockKey: string; ttl: number }): Promise<Lock> {
		try {
			this.logger.log('Acquiring lock', { lockKey, ttlMs: ttl });
			return await this.redlock.acquire([lockKey], ttl);
		} catch (error) {
			this.logger.error(`Failed to acquire lock: ${error}`);
			throw error;
		}
	}

	async releaseLock({ lock }: { lock: Lock }): Promise<void> {
		try {
			this.logger.log('Releasing lock', { lockKey: lock.resources.join(',') });
			await lock.release();
		} catch (error) {
			this.logger.error(`Failed to release lock: ${error}`);
			throw error;
		}
	}

	private getNamespacedKey({
		namespace,
		key,
	}: {
		namespace: Namespaces;
		key: string;
	}): string {
		return `${namespace}:${key}`;
	}

	private shouldReadFromMaster({
		key,
		consistencyLevel,
	}: {
		namespace: Namespaces;
		key: string;
		consistencyLevel: ConsistencyLevel;
	}): boolean {
		if (consistencyLevel === ConsistencyLevel.STRONG) {
			return true;
		}

		if (!this.isReadReplicaHealthy) {
			return true;
		}

		const lastWriteTime = this.recentWrites.get(key);
		if (lastWriteTime) {
			const timeSinceWrite = Date.now() - lastWriteTime;
			return timeSinceWrite < this.CONSISTENCY_WINDOW_MS;
		}

		return false;
	}

	private trackRecentWrite({ key }: { key: string }): void {
		this.recentWrites.set(key, Date.now());
	}

	private startRecentWritesCleanup(): void {
		setInterval(() => {
			const now = Date.now();
			for (const [key, timestamp] of this.recentWrites.entries()) {
				if (now - timestamp > this.CONSISTENCY_WINDOW_MS * 2) {
					this.recentWrites.delete(key);
				}
			}
		}, this.CONSISTENCY_WINDOW_MS).unref();
	}

	private setupHealthChecks(): void {
		this.redisReadClient.on('error', (error) => {
			this.logger.error('Read replica connection error:', error);
			this.isReadReplicaHealthy = false;
		});

		this.redisReadClient.on('ready', () => {
			this.logger.log('Read replica connection restored');
			this.isReadReplicaHealthy = true;
		});

		this.redisWriteClient.on('error', (error) => {
			this.logger.error('Write client connection error:', error);
		});
	}

	private createCacheError({
		code,
		originalError,
	}: {
		code: CacheError['code'];
		originalError?: Error;
	}): CacheError {
		const error = new Error(`Cache operation failed: ${code}`) as CacheError;
		error.code = code;
		if (originalError) {
			error.originalError = originalError;
		}
		return error;
	}
}

