import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';
import { Redis } from 'ioredis';
import Keyv from 'keyv';
import { Lock } from 'redlock';

import {
	CACHE_READ_MANAGER,
	CACHE_WRITE_MANAGER,
	REDIS_READ_CLIENT,
	REDIS_WRITE_CLIENT,
} from '@modules/cache/cache.constant';
import { CacheService } from '@modules/cache/cache.service';
import {
	ConsistencyLevel,
	Namespaces,
} from '@modules/cache/types/cache.interface';

const mockCacheWriteManager = {
	get: jest.fn(),
	set: jest.fn(),
	delete: jest.fn(),
	clear: jest.fn(),
};

const mockCacheReadManager = {
	get: jest.fn(),
	set: jest.fn(),
	delete: jest.fn(),
	clear: jest.fn(),
};

const mockRedisWriteClient = {
	incr: jest.fn(),
	on: jest.fn(),
};

const mockRedisReadClient = {
	on: jest.fn(),
};

const mockLock = {
	resources: ['test-lock'],
	release: jest.fn(),
};

const mockRedlock = {
	acquire: jest.fn().mockResolvedValue(mockLock),
};

jest.mock('redlock', () => {
	return jest.fn().mockImplementation(() => mockRedlock);
});

describe('CacheService', () => {
	let service: CacheService;

	beforeEach(async () => {
		const module: TestingModule = await Test.createTestingModule({
			providers: [
				CacheService,
				{ provide: CACHE_WRITE_MANAGER, useValue: mockCacheWriteManager },
				{ provide: CACHE_READ_MANAGER, useValue: mockCacheReadManager },
				{ provide: REDIS_WRITE_CLIENT, useValue: mockRedisWriteClient },
				{ provide: REDIS_READ_CLIENT, useValue: mockRedisReadClient },
			],
		}).compile();

		service = module.get<CacheService>(CacheService);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	describe('get', () => {
		it('should read from replica with EVENTUAL consistency', async () => {
			const testValue = { data: 'test' };
			mockCacheReadManager.get.mockResolvedValue(testValue);

			const result = await service.get({
				namespace: Namespaces.SESSION,
				key: 'test-key',
				consistencyLevel: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalledWith('session:test-key');
			expect(mockCacheWriteManager.get).not.toHaveBeenCalled();
			expect(result).toEqual(testValue);
		});

		it('should read from master with STRONG consistency', async () => {
			const testValue = { data: 'test' };
			mockCacheWriteManager.get.mockResolvedValue(testValue);

			const result = await service.get({
				namespace: Namespaces.SESSION,
				key: 'test-key',
				consistencyLevel: ConsistencyLevel.STRONG,
			});

			expect(mockCacheWriteManager.get).toHaveBeenCalledWith('session:test-key');
			expect(mockCacheReadManager.get).not.toHaveBeenCalled();
			expect(result).toEqual(testValue);
		});

		it('should fall back to master when replica is unhealthy', async () => {
			const testValue = { data: 'test' };
			mockCacheReadManager.get.mockRejectedValueOnce(new Error('connection failed'));
			mockCacheWriteManager.get.mockResolvedValue(testValue);

			const result = await service.get({
				namespace: Namespaces.SESSION,
				key: 'test-key',
				consistencyLevel: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalled();
			expect(mockCacheWriteManager.get).toHaveBeenCalled();
			expect(result).toEqual(testValue);
		});

		it('should read from master when key was recently written', async () => {
			const testValue = { data: 'test' };
			mockCacheWriteManager.get.mockResolvedValue(testValue);
			mockCacheWriteManager.set.mockResolvedValue(undefined);

			await service.set({
				namespace: Namespaces.SESSION,
				key: 'test-key',
				value: testValue,
			});

			jest.clearAllMocks();
			mockCacheWriteManager.get.mockResolvedValue(testValue);

			const result = await service.get({
				namespace: Namespaces.SESSION,
				key: 'test-key',
				consistencyLevel: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheWriteManager.get).toHaveBeenCalledWith('session:test-key');
			expect(mockCacheReadManager.get).not.toHaveBeenCalled();
			expect(result).toEqual(testValue);
		});

		it('should return null on cache miss', async () => {
			mockCacheReadManager.get.mockResolvedValue(undefined);

			const result = await service.get({
				namespace: Namespaces.SESSION,
				key: 'missing-key',
			});

			expect(result).toBeNull();
		});
	});

	describe('set', () => {
		it('should write to master and track recent write', async () => {
			mockCacheWriteManager.set.mockResolvedValue(undefined);

			await service.set({
				namespace: Namespaces.AUTH_CODE,
				key: 'my-key',
				value: 'my-value',
				ttl: 3000,
			});

			expect(mockCacheWriteManager.set).toHaveBeenCalledWith(
				'auth-code:my-key',
				'my-value',
				3000,
			);
		});

		it('should throw CacheError when set fails', async () => {
			mockCacheWriteManager.set.mockRejectedValue(new Error('write failure'));

			await expect(
				service.set({ namespace: Namespaces.SESSION, key: 'k', value: 'v' }),
			).rejects.toMatchObject({ code: 'OPERATION_FAILED' });
		});
	});

	describe('deleteOne', () => {
		it('should remove key from write manager and return true', async () => {
			mockCacheWriteManager.delete.mockResolvedValue(true);

			const result = await service.deleteOne({
				namespace: Namespaces.SESSION,
				key: 'delete-me',
			});

			expect(mockCacheWriteManager.delete).toHaveBeenCalledWith('session:delete-me');
			expect(result).toBe(true);
		});

		it('should return false when delete fails', async () => {
			mockCacheWriteManager.delete.mockRejectedValue(new Error('delete error'));

			const result = await service.deleteOne({
				namespace: Namespaces.SESSION,
				key: 'fail-key',
			});

			expect(result).toBe(false);
		});
	});

	describe('deleteAll', () => {
		it('should clear both managers and return true', async () => {
			mockCacheWriteManager.clear.mockResolvedValue(undefined);
			mockCacheReadManager.clear.mockResolvedValue(undefined);

			const result = await service.deleteAll({ namespace: Namespaces.SESSION });

			expect(mockCacheWriteManager.clear).toHaveBeenCalled();
			expect(mockCacheReadManager.clear).toHaveBeenCalled();
			expect(result).toBe(true);
		});
	});

	describe('incrementByOne', () => {
		it('should call INCR on write client', async () => {
			mockRedisWriteClient.incr.mockResolvedValue(1);

			await service.incrementByOne({ namespace: Namespaces.SESSION, key: 'counter' });

			expect(mockRedisWriteClient.incr).toHaveBeenCalledWith('session:counter');
		});

		it('should throw when INCR fails', async () => {
			mockRedisWriteClient.incr.mockRejectedValue(new Error('incr error'));

			await expect(
				service.incrementByOne({ namespace: Namespaces.SESSION, key: 'counter' }),
			).rejects.toThrow('incr error');
		});
	});

	describe('withLock', () => {
		it('should acquire and release lock around operation', async () => {
			const operationResult = 'result';
			const operation = jest.fn().mockResolvedValue(operationResult);

			const result = await service.withLock({
				lockKey: 'my-lock',
				operation,
				ttl: 3000,
			});

			expect(mockRedlock.acquire).toHaveBeenCalledWith(['my-lock'], 3000);
			expect(operation).toHaveBeenCalled();
			expect(mockLock.release).toHaveBeenCalled();
			expect(result).toBe(operationResult);
		});

		it('should release lock even when operation throws', async () => {
			const operation = jest.fn().mockRejectedValue(new Error('operation failed'));

			await expect(
				service.withLock({ lockKey: 'error-lock', operation }),
			).rejects.toThrow('operation failed');

			expect(mockLock.release).toHaveBeenCalled();
		});
	});

	describe('acquireLock', () => {
		it('should return a Lock object', async () => {
			const lock = await service.acquireLock({ lockKey: 'acquire-lock', ttl: 5000 });

			expect(mockRedlock.acquire).toHaveBeenCalledWith(['acquire-lock'], 5000);
			expect(lock).toBe(mockLock);
		});
	});

	describe('releaseLock', () => {
		it('should call release on the provided lock', async () => {
			await service.releaseLock({ lock: mockLock as unknown as Lock });

			expect(mockLock.release).toHaveBeenCalled();
		});
	});

	describe('has', () => {
		it('should return true when key exists', async () => {
			mockCacheReadManager.get.mockResolvedValue({ data: 'value' });

			const result = await service.has({ namespace: Namespaces.SESSION, key: 'exists' });

			expect(result).toBe(true);
		});

		it('should return false when key does not exist', async () => {
			mockCacheReadManager.get.mockResolvedValue(undefined);

			const result = await service.has({
				namespace: Namespaces.SESSION,
				key: 'missing',
			});

			expect(result).toBe(false);
		});
	});
});

